import{_ as t,c as o,o as r,a1 as a}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"隐私: 数据安全防护 | opencode-supermemory","description":"掌握 opencode-supermemory 的隐私安全机制。学习使用 private 标签脱敏敏感数据，安全配置 API Key，理解数据上传和本地存储流程。","frontmatter":{"title":"隐私: 数据安全防护 | opencode-supermemory","sidebarTitle":"隐私安全","subtitle":"隐私: 数据安全防护 | opencode-supermemory","description":"掌握 opencode-supermemory 的隐私安全机制。学习使用 private 标签脱敏敏感数据，安全配置 API Key，理解数据上传和本地存储流程。","tags":["Privacy","Security","Configuration"],"prerequisite":["start-getting-started"],"order":999},"headers":[],"relativePath":"supermemoryai/opencode-supermemory/security/privacy/index.md","filePath":"supermemoryai/opencode-supermemory/security/privacy/index.md"}'),i={name:"supermemoryai/opencode-supermemory/security/privacy/index.md"};function n(s,e,c,l,d,p){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="privacy-and-data-security-protecting-your-sensitive-information" tabindex="-1">Privacy and Data Security: Protecting Your Sensitive Information <a class="header-anchor" href="#privacy-and-data-security-protecting-your-sensitive-information" aria-label="Permalink to &quot;Privacy and Data Security: Protecting Your Sensitive Information&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li><strong>Understand Data Flow</strong>: Know exactly what data is uploaded to the cloud and what stays local.</li><li><strong>Master Data Redaction</strong>: Learn to use the <code>&lt;private&gt;</code> tag to prevent sensitive information (like passwords and keys) from being uploaded.</li><li><strong>Secure Key Management</strong>: Learn the safest way to configure your <code>SUPERMEMORY_API_KEY</code>.</li></ul><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><p>When using opencode-supermemory, understanding the data flow is crucial:</p><ol><li><strong>Cloud Storage</strong>: Your Memories are stored in Supermemory&#39;s cloud database, not in local files. This means you need an internet connection to access them.</li><li><strong>Local Redaction</strong>: To protect privacy, the plugin redacts data locally <strong>before</strong> sending it to the cloud.</li><li><strong>Explicit Control</strong>: The plugin does not automatically scan all file uploads. Content is processed only when the Agent explicitly calls the <code>add</code> tool or triggers compression.</li></ol><h3 id="redaction-mechanism" tabindex="-1">Redaction Mechanism <a class="header-anchor" href="#redaction-mechanism" aria-label="Permalink to &quot;Redaction Mechanism&quot;">​</a></h3><p>The plugin includes a built-in filter specifically designed to recognize <code>&lt;private&gt;</code> tags.</p><ul><li><strong>Input</strong>: <code>The database password here is &lt;private&gt;123456&lt;/private&gt;</code></li><li><strong>Process</strong>: The plugin detects the tag and replaces its content with <code>[REDACTED]</code>.</li><li><strong>Upload</strong>: <code>The database password here is [REDACTED]</code></li></ul><div class="info custom-block"><p class="custom-block-title">Note</p><p>This process happens internally within the plugin code and is completed before any data leaves your computer.</p></div><h2 id="step-by-step-guide" tabindex="-1">Step-by-Step Guide <a class="header-anchor" href="#step-by-step-guide" aria-label="Permalink to &quot;Step-by-Step Guide&quot;">​</a></h2><h3 id="step-1-securely-configure-api-key" tabindex="-1">Step 1: Securely Configure API Key <a class="header-anchor" href="#step-1-securely-configure-api-key" aria-label="Permalink to &quot;Step 1: Securely Configure API Key&quot;">​</a></h3><p>While you can write the API Key directly into the configuration file, to prevent accidental leakage (e.g., sharing the config file by mistake), we recommend understanding the priority logic.</p><p><strong>Priority Rules</strong>:</p><ol><li><strong>Configuration File</strong> (<code>~/.config/opencode/supermemory.jsonc</code>): Highest priority.</li><li><strong>Environment Variable</strong> (<code>SUPERMEMORY_API_KEY</code>): Used if not set in the configuration file.</li></ol><p><strong>Recommended Practice</strong>: If you need flexibility or are running in a CI/CD environment, use environment variables. If you are an individual developer, configuring it in the user directory&#39;s JSONC file is also safe (as it is not in your project&#39;s Git repository).</p><h3 id="step-2-using-the-private-tag" tabindex="-1">Step 2: Using the <code>&lt;private&gt;</code> Tag <a class="header-anchor" href="#step-2-using-the-private-tag" aria-label="Permalink to &quot;Step 2: Using the `&lt;private&gt;` Tag&quot;">​</a></h3><p>When you ask the Agent to remember content containing sensitive information via natural language, you can wrap the sensitive parts with the <code>&lt;private&gt;</code> tag.</p><p><strong>Demo</strong>:</p><p>Tell the Agent:</p><blockquote><p>Please remember, the production database IP is 192.168.1.10, but the root password is <code>&lt;private&gt;SuperSecretPwd!&lt;/private&gt;</code>, do not leak the password.</p></blockquote><p><strong>What You Should See</strong>: The Agent will call the <code>supermemory</code> tool to save the memory. Although the Agent&#39;s response might contain the password (because it&#39;s in the context), the <strong>actual memory saved to the Supermemory cloud</strong> has been redacted.</p><h3 id="step-3-verify-redaction-results" tabindex="-1">Step 3: Verify Redaction Results <a class="header-anchor" href="#step-3-verify-redaction-results" aria-label="Permalink to &quot;Step 3: Verify Redaction Results&quot;">​</a></h3><p>We can verify that the password was not stored by searching for it.</p><p><strong>Action</strong>: Ask the Agent to search for the memory just saved:</p><blockquote><p>Search for the production database password.</p></blockquote><p><strong>Expected Result</strong>: The content retrieved by the Agent from Supermemory should be: <code>The production database IP is 192.168.1.10, but the root password is [REDACTED]...</code></p><p>If the Agent tells you &quot;The password is [REDACTED]&quot;, it means the redaction mechanism is working correctly.</p><h2 id="common-misconceptions" tabindex="-1">Common Misconceptions <a class="header-anchor" href="#common-misconceptions" aria-label="Permalink to &quot;Common Misconceptions&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Myth 1: All code is uploaded</p><p><strong>Fact</strong>: The plugin does <strong>not</strong> automatically upload your entire codebase. It only uploads specific snippets when you run <code>/supermemory-init</code> for an initial scan, or when the Agent explicitly decides to &quot;remember&quot; a specific piece of code logic.</p></div><div class="warning custom-block"><p class="custom-block-title">Myth 2: .env files are automatically loaded</p><p><strong>Fact</strong>: The plugin reads the <code>SUPERMEMORY_API_KEY</code> from the process environment. If you place a <code>.env</code> file in the project root, the plugin will <strong>not</strong> automatically read it unless your terminal or the OpenCode main program has loaded it.</p></div><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Number</th></tr></thead><tbody><tr><td>Privacy Redaction Logic</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/privacy.ts#L1-L13" target="_blank" rel="noreferrer"><code>src/services/privacy.ts</code></a></td><td>1-13</td></tr><tr><td>API Key Loading</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/config.ts#L90" target="_blank" rel="noreferrer"><code>src/config.ts</code></a></td><td>90</td></tr><tr><td>Plugin Call Redaction</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L282" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>282</td></tr></tbody></table><p><strong>Key Functions</strong>:</p><ul><li><code>stripPrivateContent(content)</code>: Performs regex replacement to turn <code>&lt;private&gt;</code> content into <code>[REDACTED]</code>.</li><li><code>loadConfig()</code>: Loads the local configuration file, with higher priority than environment variables.</li></ul></details><h2 id="what-s-next" tabindex="-1">What&#39;s Next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next&quot;">​</a></h2><blockquote><p>Congratulations on completing the core course of opencode-supermemory!</p><p>Next, you can:</p><ul><li>Review <a href="/docs/opencodedocs/supermemoryai/opencode-supermemory/advanced/configuration/">Advanced Configuration</a> to learn more about customization options.</li></ul></blockquote>',35)])])}const m=t(i,[["render",n]]);export{h as __pageData,m as default};
